import React from 'react';
import { Link } from 'react-router-dom';

function Services() {
  const serviceData = [
    { id: 1, title: "Web Development", icon: "fas fa-code", desc: "Modern, responsive websites built with React and Node.js.", color: "#0d6efd" },
    { id: 2, title: "UI/UX Design", icon: "fas fa-paint-brush", desc: "Creative and user-friendly interface designs for best UX.", color: "#dc3545" },
    { id: 3, title: "App Development", icon: "fas fa-mobile-alt", desc: "Custom Android and iOS applications with high performance.", color: "#198754" },
    { id: 4, title: "Assignment Support", icon: "fas fa-book-open", desc: "Expert help for academic projects and technical assignments.", color: "#ffc107" },
    { id: 5, title: "PPT Design", icon: "fas fa-file-powerpoint", desc: "Professional presentations for business and college meetings.", color: "#0dcaf0" },
    { id: 6, title: "Report Writing", icon: "fas fa-file-alt", desc: "Detailed technical and business report writing services.", color: "#6c757d" }
  ];

  return (
    <div className="services-page bg-light pb-5">
      {/* Header Section */}
      <header className="py-5 bg-dark text-white text-center mb-5 shadow">
        <div className="container">
          <h1 className="fw-bold display-5">My <span className="text-primary">Professional</span> Services</h1>
          <p className="lead opacity-75">Tailored solutions for your digital and academic success.</p>
        </div>
      </header>

      {/* Services Grid */}
      <section className="container">
        <div className="row g-4">
          {serviceData.map((service) => (
            <div className="col-md-4" key={service.id}>
              <div className="card h-100 border-0 shadow-sm p-4 text-center service-card">
                {/* Icon Box */}
                <div className="icon-wrapper mx-auto mb-4" style={{ backgroundColor: `${service.color}15`, color: service.color }}>
                  <i className={`${service.icon} fa-2x`}></i>
                </div>
                
                <h4 className="fw-bold mb-3" style={{ color: '#2c3e50' }}>{service.title}</h4>
                <p className="text-muted small mb-4 px-2">{service.desc}</p>
                
                <Link to="/register" className="btn mt-auto rounded-pill fw-bold shadow-sm action-btn" style={{ borderColor: service.color, color: service.color }}>
                  Get Started <i className="fas fa-arrow-right ms-2 small"></i>
                </Link>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* --- PROFESSIONAL CSS --- */}
      <style>{`
        .service-card {
          transition: all 0.3s ease-in-out;
          border-radius: 20px;
          background: #ffffff;
        }
        
        .service-card:hover {
          transform: translateY(-10px);
          box-shadow: 0 15px 30px rgba(0,0,0,0.1) !important;
        }

        .icon-wrapper {
          width: 70px;
          height: 70px;
          line-height: 75px;
          border-radius: 50%;
          display: flex;
          align-items: center;
          justify-content: center;
          transition: 0.3s;
        }

        .service-card:hover .icon-wrapper {
          transform: rotateY(360deg);
        }

        .action-btn {
          padding: 8px 25px;
          font-size: 0.9rem;
          transition: 0.3s;
          border: 2px solid;
        }

        .action-btn:hover {
          background-color: currentColor;
          color: #fff !important;
          border-color: transparent;
        }

        .bg-light { background-color: #f8f9fa !important; }
      `}</style>
    </div>
  );
}

export default Services;
